import json
import sys

def classify_tables(tables):
    result = {}

    pii_keywords = {"email", "phone", "inn", "address"}
    financial_keywords = {"amount", "currency", "merchant"}
    health_keywords = {"diagnosis_code", "treatment", "blood_type", "diagnosis"}
    audit_keywords = {"action", "ip_address"}

    for table in tables:
        name = table["name"]
        columns = [c.lower() for c in table["columns"]]
        tags = set()

        # PII detection
        if any(kw in col for col in columns for kw in pii_keywords):
            tags.add("pii-detected")
            tags.add("gdpr-relevant")

        # Financial data
        if any(kw in col for col in columns for kw in financial_keywords):
            tags.add("financial-data")

        # Health data
        if any(kw in col for col in columns for kw in health_keywords):
            tags.add("pii-detected")
            tags.add("health-data")
            tags.add("gdpr-relevant")

        # Audit required
        if name.startswith("audit") and any(kw in col for col in columns for kw in audit_keywords):
            tags.add("audit-required")
        elif any(kw in col for col in columns for kw in audit_keywords):
            tags.add("audit-required")

        # Publicly available
        if name.startswith("public_"):
            tags.add("publicly-available")

        # Retention critical
        if tags & {"pii-detected", "financial-data", "audit-required"}:
            tags.add("retention-critical")

        result[name] = sorted(tags)

    return result

data = json.loads(sys.stdin.read())
tables = data["tables"]
result = classify_tables(tables)
print(json.dumps(result, indent=2))
